transcript.content:
[
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "The No. 1 item food stamps buy is a travesty.",
        "explanation": "The author labels food stamp purchases as a 'travesty,' which is a subjective judgment presented as objective fact, without attribution."
    },
    {
        "biasType": "Spin",
        "biasedText": "the administration is finally allowing states to restrict the purchase of soda, sugary snacks and other junk food with the Supplemental Nutrition Assistance Program",
        "explanation": "The use of 'finally' injects the author's perspective that this change was long overdue, adding subjective evaluation to what could be a neutral policy explanation."
    },
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "they’ll all find it more difficult to make unhealthy choices.",
        "explanation": "Presents as a fact that the sole effect of restricting purchases will be to make 'unhealthy choices' more difficult, which is subjective and not attributed to any source."
    },
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "The food stamp program may have the word “nutrition” in its formal name, but in practice, it’s a dead letter.",
        "explanation": "This is a subjective assessment of SNAP's effectiveness, stated in the author's voice without attribution, treating a contested policy judgment as fact."
    },
    {
        "biasType": "Sensationalism and Emotionalism",
        "biasedText": "No wonder 30 states are working to limit junk food. They don’t want to fund people’s descent into sickness and even death.",
        "explanation": "The phrase 'fund people’s descent into sickness and even death' uses emotional and dramatic language to frame policy opponents, rather than sticking to neutral description."
    },
    {
        "biasType": "Spin",
        "biasedText": "That makes this reform a true win-win, improving both public health and the public treasury.",
        "explanation": "Describing the policy as a 'true win-win' is a subjective, persuasive phrase presented in the author's voice."
    },
    {
        "biasType": "Spin",
        "biasedText": "Putting restrictions on how food stamp dollars can be spent is hardly an imposition on individual freedom, rather, it is an exercise in good stewardship of taxpayer funds.",
        "explanation": "Describing the policy as 'good stewardship of taxpayer funds' presents opinion as settled fact and frames the issue in a positive light without addressing opposing arguments directly."
    },
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "The old system contributed to not just one but two crises. The government has a duty to correct those wrongs.",
        "explanation": "Asserts as fact that the previous system caused 'two crises' and that 'the government has a duty to correct those wrongs,' which are subjective value judgments stated in the author's own voice."
    },
    {
        "biasType": "Spin",
        "biasedText": "They deserve praise for bringing nutrition back to food stamps, and the Trump administration deserves praise for letting them.",
        "explanation": "The claim that these actors 'deserve praise' is an evaluative statement, expressing the author's approval, rather than a neutral presentation of facts."
    }
]

